Deno.serve(async (req) => {
  // Handle CORS
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("Authorization");
    if (!authHeader) {
      return new Response(
        JSON.stringify({ error: "No authorization header" }),
        { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY")!;
    
    const supabase = createClient(supabaseUrl, supabaseAnonKey, {
      global: { headers: { Authorization: authHeader } },
    });

    // Get the current user
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return new Response(
        JSON.stringify({ error: "Unauthorized" }),
        { status: 401, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const userId = user.id;
    const results = { exchanges: 0, sectors: 0, industries: 0, instruments: 0, errors: [] as string[] };

    // Seed exchanges
    const exchangeRecords = exchanges.map((e, i) => ({
      user_id: userId,
      list_type: "exchanges",
      code: e.code,
      name: e.name,
      description: e.description,
      metadata: { icon: e.icon },
      display_order: i + 1,
      is_active: true,
    }));

    const { error: exchangeError } = await supabase
      .from("admin_general_lists")
      .upsert(exchangeRecords, { onConflict: "user_id,list_type,code", ignoreDuplicates: true });

    if (exchangeError) {
      results.errors.push(`Exchanges: ${exchangeError.message}`);
    } else {
      results.exchanges = exchanges.length;
    }

    // Seed sectors
    const sectorRecords = sectors.map((s, i) => ({
      user_id: userId,
      list_type: "sectors",
      code: s.code,
      name: s.name,
      description: s.description,
      metadata: { icon: s.icon },
      display_order: i + 1,
      is_active: true,
    }));

    const { error: sectorError } = await supabase
      .from("admin_general_lists")
      .upsert(sectorRecords, { onConflict: "user_id,list_type,code", ignoreDuplicates: true });

    if (sectorError) {
      results.errors.push(`Sectors: ${sectorError.message}`);
    } else {
      results.sectors = sectors.length;
    }

    // Seed industries
    const industryRecords = industries.map((ind, i) => ({
      user_id: userId,
      list_type: "industries",
      code: ind.code,
      name: ind.name,
      description: ind.description,
      metadata: { icon: ind.icon, sector: ind.sector },
      display_order: i + 1,
      is_active: true,
    }));

    const { error: industryError } = await supabase
      .from("admin_general_lists")
      .upsert(industryRecords, { onConflict: "user_id,list_type,code", ignoreDuplicates: true });

    if (industryError) {
      results.errors.push(`Industries: ${industryError.message}`);
    } else {
      results.industries = industries.length;
    }

    // Helper to create instrument records
    const createInstrumentRecords = (instruments: typeof nyseInstruments, exchangeCode: string, domicile: string) => {
      return instruments.map((inst) => ({
        user_id: userId,
        name: inst.name,
        code: inst.code,
        isin: inst.isin,
        morningstar_id: inst.morningstar_id,
        exchange: exchangeCode,
        sector: inst.sector,
        industry: inst.industry,
        fund_type: "Share",
        domicile: domicile,
        is_active: true,
      }));
    };

    // Seed all instruments by exchange
    const allInstruments = [
      ...createInstrumentRecords(nyseInstruments, "NYSE", "US"),
      ...createInstrumentRecords(nasdaqInstruments, "NASDAQ", "US"),
      ...createInstrumentRecords(jseInstruments, "JSE", "ZA"),
      ...createInstrumentRecords(tseInstruments, "TSE", "JP"),
      ...createInstrumentRecords(sseInstruments, "SSE", "CN"),
      ...createInstrumentRecords(lseInstruments, "LSE", "GB"),
      ...createInstrumentRecords(asxInstruments, "ASX", "AU"),
      ...createInstrumentRecords(tsxInstruments, "TSX", "CA"),
    ];

    // Insert in batches of 100 to avoid timeout
    const batchSize = 100;
    let successCount = 0;

    for (let i = 0; i < allInstruments.length; i += batchSize) {
      const batch = allInstruments.slice(i, i + batchSize);
      const { error: instrumentError } = await supabase
        .from("admin_funds")
        .upsert(batch, { onConflict: "user_id,code,exchange", ignoreDuplicates: true });

      if (instrumentError) {
        results.errors.push(`Instruments batch ${i / batchSize + 1}: ${instrumentError.message}`);
      } else {
        successCount += batch.length;
      }
    }

    results.instruments = successCount;

    return new Response(
      JSON.stringify({
        success: results.errors.length === 0,
        message: `Seeded ${results.exchanges} exchanges, ${results.sectors} sectors, ${results.industries} industries, and ${results.instruments} instruments`,
        results,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("Error seeding instruments data:", error);
    return new Response(
      JSON.stringify({ error: error.message }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});
